#!&#x2F;bin&#x2F;bash
mysql物理备份脚本每周日进行全量备份，周一到周六进行增量备份，7天为一个周期备份路径、日志路径backup_dir=&quot;/backup&quot;log_dir=&quot;/backup/log&quot;full_backup_dir=&quot;/backup/full&quot;inc_backup_dir=&quot;/backup/inc&quot;log_date=$(date &quot;+%F-%T&quot;)
数据库用户、密码MY_USER=rootMY_PASS=P@ssword1
判断日志、备份路径是否存在[ -d $backup_dir ] || mkdir $backup_dir[ -d $log_dir ] || mkdir $log_dir[ -d $full_backup_dir ] || mkdir $full_backup_dir[ -d $inc_backup_dir ] || mkdir $inc_backup_dir
全量备份函数full_backup()&#123;	# 全量备份命令 	innobackupex --user=$MY_USER --password=$MY_PASS $full_backup_dir	if [ $? -eq 0 ];then		echo &quot;$&#123;log_date&#125; full backup!!!&quot; &gt;&gt; $log_dir/back.log	else		echo &quot;$&#123;log_date&#125; full failed!!&quot; &gt;&gt; $log_dir/err.log	fi&#125;
获取上周日的时间,以%Y-%m-%d格式显示sunday=$(date -d &quot;last sunday&quot; +%F)
获取前一天的时间,以%Y-%m-%d格式显示yesterday=$(date -d &quot;yesterday&quot; +%F)
增量备份函数inc_backup()&#123;	# 判断当前时间是否为周一(周一需要去找全量备份，周二到周六找前一天的备份)	if [ $week_date -eq 1 ];then		# 查找全量备份的文件路径		local full_backup_dir=$(find $backup_dir -name $&#123;sunday&#125;*)		innobackupex --user=$MY_USER --password=$MY_PASS --incremental $&#123;inc_backup_dir&#125; --incremental-basedir=$&#123;full_backup_dir&#125;		# 判断命令是否执行成功,写入日志文件    	if [ $? -eq 0 ];then        	echo &quot;$&#123;log_date&#125; inc backup!!!&quot; &gt;&gt; $log_dir/back.log    	else        	echo &quot;$&#123;log_date&#125; inc failed!!&quot; &gt;&gt; $log_dir/err.log    	fi	else		# 查找前一天的文件路径        local yesterday_backup_dir=$(find $backup_dir -name $&#123;yesterday&#125;*)        innobackupex --user=$MY_USER --password=$MY_PASS --incremental $&#123;inc_backup_dir&#125; --incremental-basedir=$&#123;yesterday_backup_dir&#125;		# 判断命令是否执行成功,写入日志文件    	if [ $? -eq 0 ];then        	echo &quot;$&#123;log_date&#125; inc backup!!!&quot; &gt;&gt; $log_dir/back.log    	else        	echo &quot;$&#123;log_date&#125; inc failed!!&quot; &gt;&gt; $log_dir/err.log    	fi	fi&#125;
查看当前是周几week_date=$(date +%u)
判断当前是周几，周日则执行全量备份，周一到周六执行增量备份if [ $week_date -eq 7 ];then	full_backupelse	inc_backup	fi

