一、使用子域名（方案一）server &#123;    listen 80;    server_name service1.example.com;    location / &#123;        proxy_pass http://localhost:3000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;&#125;server &#123;    listen 80;    server_name service2.example.com;    location / &#123;        proxy_pass http://localhost:4000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;&#125;

二、使用同一个域名(方案二)server &#123;    listen 80;    server_name example.com;    location /service1 &#123;        proxy_pass http://localhost:3000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;    location /service2 &#123;        proxy_pass http://localhost:4000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;&#125;

配置ssl证书# 1、安装Certbot，Certbot是一个自动化工具，可以帮助你获取和安装SSL证书# 对于Ubuntu/Debiansudo apt updatesudo apt install certbot python3-certbot-nginx# 对于CentOS/RHELsudo yum install epel-releasesudo yum install certbot python3-certbot-nginx# 2. 获取SSL证书，使用Certbot为每个子域名获取SSL证书：sudo certbot --nginx -d service1.example.com -d service2.example.com

配置nginxserver &#123;    listen 80;    server_name service1.example.com;    return 301 https://$host$request_uri;&#125;server &#123;    listen 443 ssl;    server_name service1.example.com;    ssl_certificate /etc/letsencrypt/live/service1.example.com/fullchain.pem;    ssl_certificate_key /etc/letsencrypt/live/service1.example.com/privkey.pem;    location / &#123;        proxy_pass http://localhost:3000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;&#125;server &#123;    listen 80;    server_name service2.example.com;    return 301 https://$host$request_uri;&#125;server &#123;    listen 443 ssl;    server_name service2.example.com;    ssl_certificate /etc/letsencrypt/live/service2.example.com/fullchain.pem;    ssl_certificate_key /etc/letsencrypt/live/service2.example.com/privkey.pem;    location / &#123;        proxy_pass http://localhost:4000;        proxy_set_header Host $host;        proxy_set_header X-Real-IP $remote_addr;        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;        proxy_set_header X-Forwarded-Proto $scheme;    &#125;&#125;



自动续费Let&#x27;s Encrypt的证书有效期为90天。Certbot会自动设置一个cron任务来续期证书。你可以手动测试续期sudo certbot renew --dry-run

!&#x2F;bin&#x2F;bash本脚本用于系统工具打印当前系统登录用户print_logged_in_users() &#123;    who | awk &#x27;&#123;print $1&#125;&#x27; | sort | uniq&#125;# 根据用户输入判断软件是否已安装并打印软件信息check_and_print_software_info() &#123;    read -p &quot;请输入要检查的软件名称： &quot; software_name    if command -v &quot;$software_name&quot; &amp;&gt; /dev/null; then        echo &quot;$software_name 已安装&quot;        # TODO: 打印软件信息命令    else        echo &quot;$software_name 未安装&quot;    fi&#125;
输入时间段和日志路径统计 nginx 访问日志次数最多的 IPanalyze_nginx_log() &#123;    read -p &quot;请输入日志路径： &quot; log_path    read -p &quot;请输入开始时间（格式：15/Jul/2023:00:00:00）： &quot; start_time    read -p &quot;请输入结束时间（格式：15/Jul/2023:00:00:00）： &quot; end_time        sed -n &quot;/$start_time/,/$end_time/p&quot; &quot;$log_path&quot; |awk &#x27;&#123;print $1&#125;&#x27; |sort|uniq -c |sort|tail -n 1|awk &#x27;&#123;print $2&#125;&#x27;&#125;
安装指定软件install_software() &#123;    read -p &quot;请选择要安装的软件：1.Nginx 2.MySQL 3.Apache 4.Vsftpd：&quot; choice    case $choice in        1)            # 安装 Nginx            # TODO: 添加 Nginx 安装命令            ;;        2)            # 安装 MySQL            # TODO: 添加 MySQL 安装命令            ;;        3)            # 安装 Apache            # TODO: 添加 Apache 安装命令            ;;        4)            # 安装 Vsftpd            # TODO: 添加 Vsftpd 安装命令            ;;        *)            echo &quot;无效的选择&quot;            ;;    esac&#125;
获取系统 CPU 排名前 10 的进程get_top_cpu_processes() &#123;    ps aux --sort=-%cpu | head -n 11&#125;
获取系统内存排名前 10 的进程get_top_memory_processes() &#123;    ps aux --sort=-%mem | head -n 11&#125;change_IP_address()&#123;    read -p &quot;是否已经配置网卡服务[y/n]：&quot; yn    if [ $yn = n ];then    echo &quot;    IPADDR=192.168.116.111    NETMASK=255.255.255.0    GATEWAY=192.168.116.2    DNS1=192.168.116.2    以上为默认格式，仅供参考！&quot;                sed -ie &#x27;s/BOOTPROTO=dhcp/BOOTPROTO=static/;s/ONBOOT=no/ONBOOT=yes/&#x27; /etc/sysconfig/network-scripts/ifcfg-ens33        read -p &quot;请输入你设置的IP地址：&quot; ip        sed -i &quot;$ a IPADDR=$ip&quot;  /etc/sysconfig/network-scripts/ifcfg-ens33            read -p &quot;请输入掩码：&quot; net            sed -i &quot;$ a NETMASK=$net&quot; /etc/sysconfig/network-scripts/ifcfg-ens33                read -p &quot;请输入网关：&quot; way                sed -i &quot;$ a GATEWAY=$way&quot; /etc/sysconfig/network-scripts/ifcfg-ens33                    read -p &quot;请输入DNS：&quot; dns                    sed -i &quot;$ a DNS1=$dns&quot; /etc/sysconfig/network-scripts/ifcfg-ens33                        echo &quot;网卡配置成功！&quot;    else        sed -i &#x27;16,19 s/\(.*\)/#\1/&#x27;  /etc/sysconfig/network-scripts/ifcfg-ens33        echo &quot;注意，16-19段已被注释！！！&quot;        read -p &quot;是否需要配置网卡服务【y/n】：&quot; YN        if [ $YN = y ];then            echo &quot;            IPADDR=192.168.116.111            NETMASK=255.255.255.0            GATEWAY=192.168.116.2            DNS1=192.168.116.2            以上为默认格式，仅供参考！&quot;                sed -ie &#x27;s/BOOTPROTO=dhcp/BOOTPROTO=static/;s/ONBOOT=no/ONBOOT=yes/&#x27; /etc/sysconfig/network-scripts/ifcfg-ens33        read -p &quot;请输入你设置的IP地址：&quot; ipp        sed -i &quot;$ a IPADDR=$ipp&quot;  /etc/sysconfig/network-scripts/ifcfg-ens33            read -p &quot;请输入掩码：&quot; nett            sed -i &quot;$ a NETMASK=$nett&quot; /etc/sysconfig/network-scripts/ifcfg-ens33                read -p &quot;请输入网关：&quot; wayy                sed -i &quot;$ a GATEWAY=$wayy&quot; /etc/sysconfig/network-scripts/ifcfg-ens33                    read -p &quot;请输入DNS：&quot; dnss                    sed -i &quot;$ a DNS1=$dnss&quot;  /etc/sysconfig/network-scripts/ifcfg-ens33                          echo &quot;网卡配置成功！&quot;        fi    fi&#125;
关闭防火墙disable_firewall()&#123;    systemctl stop firewalld;systemctl disable firewalld;        echo &quot;防火墙已关闭,关闭开机自启服务！&quot;    sed -i &#x27;s/SELINUX=enforcing/SELINUX=disabled/g&#x27; /etc/selinux/config        echo &quot;selinux已关闭，已关闭开机自启服务！&quot;&#125;
关闭DNSon_DNS()&#123;    sed -i &#x27;115s/#UseDNS yes/UseDNS no/&#x27;    /etc/ssh/sshd_config;systemctl restart sshd    echo &quot;DNS已关闭！！！&quot;&#125;
备份backup_copy()&#123;    #每周日进行全量备份，周一到周六进行增量备份    #关闭防火墙    systemctl stop firewalld    setenforce 0    #备份路径    back_dir=&quot;/backup&quot;    log_dir=&quot;/backup_log&quot;    full_backup_dir=&quot;backup/full&quot;    inc_backup_dir=&quot;backup/inc&quot;    #变量时间    log_date=$(date &quot;+%F-%T&quot;)    #定义用户，密码    MY_USER=&quot;root&quot;    MY_PASS=&quot;1&quot;    #验证日志目录路径是否存在    [ -d $back_dir ] || mkdir $back_dir    [ -d $log_dir ] || mkdir $log_dir    [ -d $full_backup_dir ] || mkdir $full_backup_dir    [ -d $inc_backup_dir ] || mkdir $inc_backup_dir    #全量备份函数    full_back()&#123;    #全量备份命令    innobackupex --user=$MY_USER --password=$MY_PASS $full_backup_dir    if [$? -eq 0];then        echo &quot;$&#123;log_date&#125; full OK!!!&quot; &gt;&gt; $log_dir/OK_log    else            echo &quot;$&#123;log_date&#125; NO found full!!!&quot; &gt;&gt; $log_dir/err_log    fi    &#125;       #获取上周日时间    sunday=$(date -d &quot;last sunday&quot; +%F)    #获取前一天的时间    yesterday=$(date -d &quot;yesterday&quot; +%F)    #增量备份函数    inc_back()&#123;    #判断当前时间是否是周一    if [ $week_date -eq 1 ];then        #查找文件        local full_backup_dir=$(find $backup_dir -name $&#123;sunday&#125;*)        innobackupex --user=$MY_USER --password=$MY_PASS --incremental $&#123;inc_backup_dir&#125; --incremental-basedir=$&#123;full_backup_dir&#125;        #判断是否执行成功，写入定义日志文件        if [$? -eq 0];then            echo &quot;$&#123;log_date&#125; full OK!!!&quot; &gt;&gt; $log_dir/OK_log        else            echo &quot;$&#123;log_date&#125; NO found full!!!&quot; &gt;&gt; $log_dir/err_log        fi    else        #查找前一天的文件路径        local yesterday_backup_dir=$(find $backup_dir -name $&#123;yesterday&#125;*)        innobackupex --user=$MY_USER --password=$MY_PASS --incremental $&#123;inc_backup_dir&#125; --incremental-basedir=$&#123;yesterday_backup_dir&#125;        # 判断命令是否执行成功,写入日志文件        if [$? -eq 0];then            echo &quot;$&#123;log_date&#125; full OK!!!&quot; &gt;&gt; $log_dir/OK_log        else            echo &quot;$&#123;log_date&#125; NO found full!!!&quot; &gt;&gt; $log_dir/err_log        fi    fi    &#125;    #查看当前时间是周几    week_date=$(date +%u)    #判断当前时间是不是周日，如果是进去全量备份，如果不是就进行增量备份    if [ $week_date -eq 7 ];then        full_backup    else        inc_backup    fi&#125;
对时check_the_time()&#123;    # 关闭防火墙    systemctl stop firewalld    setenforce 0    # 下载软件    yum -y instal ntpdate    # 查看当前时区    timedatectl    # 列出可用时区    #timedatectl list-timezones    # 修改上海时区    timedatectl set-timezone Asia/Shanghai    # 验证修改是否生效    timedatectl    # 对时    ntpdate ntp.aliyun.com    echo &quot;对时成功，当前时间为：&quot;     date +&#x27;%F %H:%M:%S&#x27;&#125;
配置IPCOPY_INSTALL()&#123;master=ip1slave=ip2read -p &quot;请输入master的IP地址：&quot; IP1read -p &quot;请输入slave的IP地址：&quot; IP2# 关闭防火墙systemctl stop firewalld;setenforce 0# 域名解析cat &gt;&gt; /etc/hosts &lt;&lt; EOF$IP1 master$IP2 slaveEOF# ping下网络ping slave &amp;&gt; /dev/nullif [ $? -eq 0 ];then    echo &quot;网络正常，可以使用&quot;else    echo &quot;sorry 网络不通&quot;fi# 添加主机配置cat &gt;&gt; /etc/my.cnf &lt;&lt; EOFlog-bin=/var/lib/mysql/masterserver-id=1gtid_mode=ONenforce_gtid_consistency=1EOF# 主机授权grant replication slave,super,reload on *.* to slave@&#x27;%&#x27; identified by &#x27;Qianfeng123!&#x27;;# 刷新权限flush privileges;# 此项为互为主从配置change master to master_host=&#x27;slave&#x27;,master_user=&#x27;slave&#x27;,master_password=&#x27;1&#x27;,master_auto_position=1;# 启动slave服务start slave;# 查看服务状态，是否有errorshow slave status\G&#125;
退出exit_menu()&#123;    echo &quot;再见！！！&quot;    break&#125;
定义菜单颜色red()&#123;    echo -e &quot;\033[31m\033[01m$1\033[0m&quot;&#125;green()&#123;    echo -e &quot;\033[32m\033[01m$1\033[0m&quot;&#125;yellow()&#123;    echo -e &quot;\033[33m\033[01m$1\033[0m&quot;&#125;blue()&#123;    echo -e &quot;\033[34m\033[01m$1\033[0m&quot;&#125;
主菜单选择main_menu() &#123;    while true; dored      &quot;===============================================&quot;green   &quot;||  ____    _____  _______  _________  _______||&quot;yellow  &quot;|| / __ \  /  _/ |/ / ___/ / __/ __/ |/ / ___/||&quot;blue    &quot;||/ /_/ / _/ //    / (_ / / _// _//    / (_ / ||&quot;yellow  &quot;||\___\_\/___/_/|_/\___/ /_/ /___/_/|_/\___/  ||&quot;green   &quot;||                                            ||&quot;red     &quot;===============================================&quot;blue    &quot;||            &gt;&gt;&gt;&gt;&gt; 清风徐来 &lt;&lt;&lt;&lt;&lt;            ||&quot;red     &quot;===============================================&quot;        echo &quot;1) 打印当前系统登录用户&quot;        echo &quot;2) 检查软件是否已安装并打印软件信息&quot;        echo &quot;3) 输入时间段和日志路径统计nginx访问日志次数最多的IP&quot;        echo &quot;4) 安装指定软件&quot;        echo &quot;5) 获取系统CPU排名前10的进程&quot;        echo &quot;6) 获取系统内存排名前10的进程&quot;        echo &quot;7) 更改IP&quot;        echo &quot;8) 关闭防火墙&quot;        echo &quot;9) 开启DNS&quot;        echo &quot;10) 备份&quot;        echo &quot;11) 对时&quot;        echo &quot;12) 主从复制&quot;        echo &quot;13) 返回上级菜单&quot;        echo &quot;14) 退出&quot;        echo &quot;============================================&quot;        read -p &quot;请输入选项： &quot; select        case $select in            1)                print_logged_in_users                ;;            2)                check_and_print_software_info                ;;            3)                analyze_nginx_log                ;;            4)                install_software                ;;            5)                get_top_cpu_processes                ;;            6)                get_top_memory_processes                ;;            7)                change_IP_address                ;;            8)                disable_firewall                ;;            9)                on_DNS                ;;            10)                backup_copy                ;;                        11)                check_the_time                ;;            12)                COPY_INSTALL                ;;            13)                echo &quot;请重新选择你需要的菜单&quot;                continue 2                ;;            14)                exit_menu                ;;            *)                echo &quot;无效的选择，请重新输入&quot;                ;;        esac        echo &quot;============================&quot;        read -p &quot;按任意键返回主菜单&quot; any_key        clear    done&#125;
运行主菜单main_menu
